import React, { useState } from "react";

function RedditTrends() {
  const [keyword, setKeyword] = useState("");
  const [posts, setPosts] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const fetchTrends = async () => {
    if (!keyword.trim()) return;
    setLoading(true);
    setError("");
    try {
      const res = await fetch(`/api/trends?q=${keyword}`);
      const data = await res.json();

      if (data.error) {
        setError(data.error);
        setPosts([]);
      } else {
        setPosts(data.posts || []);
      }
    } catch (err) {
      setError("Failed to fetch Reddit trends.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ padding: "20px", maxWidth: "700px", margin: "auto" }}>
      <h2>🔎 Reddit Trends</h2>
      <input
        type="text"
        placeholder="Enter stock or keyword (e.g. Tesla)"
        value={keyword}
        onChange={(e) => setKeyword(e.target.value)}
        style={{
          padding: "10px",
          width: "70%",
          marginRight: "10px",
          fontSize: "16px",
        }}
      />
      <button onClick={fetchTrends} style={{ padding: "10px 20px" }}>
        Search
      </button>

      {loading && <p>Loading...</p>}
      {error && <p style={{ color: "red" }}>{error}</p>}

      {posts.length > 0 && (
        <div style={{ marginTop: "20px" }}>
          <h3>Results for: {keyword}</h3>
          <ul>
            {posts.map((post, idx) => (
              <li key={idx} style={{ marginBottom: "15px" }}>
                <a href={post.url} target="_blank" rel="noopener noreferrer">
                  {post.title}
                </a>
                <p>⬆️ Score: {post.score}</p>
              </li>
            ))}
          </ul>
        </div>
      )}
    </div>
  );
}

export default RedditTrends;
